cds-views-016.codeExamples:
@AbapCatalog.sqlViewName: 'ZI_SALESORD_V'
@AbapCatalog.compiler.compareFilter: true
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Sales Order Interface View'
@VDM.viewType: #BASIC
@ObjectModel.usageType.serviceQuality: #A
@ObjectModel.usageType.sizeCategory: #XL
define view ZI_SALES_ORDER
  as select from vbak
  association [0..*] to vbap as _Items
    on $projection.SalesOrder = _Items.vbeln
  association [0..1] to kna1 as _Customer
    on $projection.Customer = _Customer.kunnr
{
  key vbak.vbeln  as SalesOrder,
      vbak.kunnr  as Customer,
      vbak.erdat  as CreationDate,
      vbak.auart  as OrderType,
      _Items,
      _Customer
}

