" Core annotations - all must be in design doc:
@AbapCatalog.sqlViewName: 'ZI_CUST_V'     " max 16 chars
@AbapCatalog.compiler.compareFilter: true
@AccessControl.authorizationCheck: #CHECK  " security
@EndUserText.label: 'Customer Interface'   " description
@VDM.viewType: #BASIC                      " layer
@ObjectModel.usageType: {
  serviceQuality: #A,
  sizeCategory: #L,
  dataClass: #MASTER
}
define view ZI_CUSTOMER
  as select from kna1
{
  key kna1.kunnr as Customer,
      kna1.name1 as CustomerName,
      kna1.land1 as Country
}

" CDS View annotation:
@AccessControl.authorizationCheck: #CHECK
define view ZI_SALES_ORG_ORDERS
  as select from vbak
{ key vbeln as SalesOrder, vkorg as SalesOrg }

" DCL Source: ZI_SALES_ORG_ORDERS
" Auth Object: V_VBAK_VKO
" Controlled field: VKORG -> SalesOrg
" Activity: ACTVT = '03' (Display)
@MappingRole: true
define role ZI_SALES_ORG_ORDERS {
  grant select on ZI_SALES_ORG_ORDERS
  where (SalesOrg) = aspect pfcg_auth(
    V_VBAK_VKO, VKORG,
    ACTVT = '03'
  );
}

" Performance-documented CDS View
@ObjectModel.usageType: {
  serviceQuality: #A,
  sizeCategory: #XL,     " >1M rows expected
  dataClass: #TRANSACTIONAL
}
" Performance note: RBKP has 50M rows in prod
" Mandatory: filter by BLDAT or BUDAT
" Index RBKP~1 supports BUKRS+BLDAT access
@AbapCatalog.buffering.status: #NOT_ALLOWED
define view ZI_INVOICE_HEADER
  as select from rbkp
{
  key rbkp.belnr as DocumentNumber,
      rbkp.bukrs as CompanyCode,
      rbkp.bldat as DocumentDate,
      rbkp.lifnr as Vendor
}
" Consumers: always add WHERE DocumentDate range

" Fiori Elements annotations - effort guide
" @UI.lineItem: List columns - 30 min/field
" @UI.selectionField: Filters - 30 min/filter
" @UI.facet: Object page sections - 1 hr/facet
" @UI.dataFieldForAction: Custom button - 2-4 hrs

@UI.headerInfo: {
  typeName: 'Purchase Order',
  typeNamePlural: 'Purchase Orders',
  title: { type: #STANDARD, value: 'PurchaseOrder' }
}
define view ZC_PO_FIORI
  as select from ZI_PURCHASE_ORDER
{
  @UI.lineItem: [{ position: 10, importance: #HIGH }]
  @UI.selectionField: [{ position: 10 }]
  key PurchaseOrder,
  @UI.lineItem: [{ position: 20 }]
      Vendor,
  @UI.lineItem: [{ position: 30 }]
      DocumentDate
}

" ATC check examples for CDS views:

" Check 1: Authorization annotation
" WARNING if missing or NOT_REQUIRED:
@AccessControl.authorizationCheck: #CHECK  " Good
@AccessControl.authorizationCheck: #NOT_REQUIRED  " ATC warns

" Check 2: SQL View Name length
@AbapCatalog.sqlViewName: 'ZI_MAT_STK_V'  " Good (12 chars)
@AbapCatalog.sqlViewName: 'ZI_MATERIAL_STOCK_VIEW'  " ERROR (>16 chars)

" Check 3: VDM type annotation
@VDM.viewType: #BASIC  " Good - ATC expects this
" (missing) -> ATC warning: VDM type not set

" Running ATC in Eclipse:
" Right-click CDS source file
" -> Run As -> ABAP Test Cockpit Check
" Results in: Window -> Show View -> Problems

