" CDS View as BW Extractor:
@Analytics.dataCategory: #FACT
@Analytics.dataExtraction.enabled: true
@Analytics.dataExtraction.delta.changeDataCapture: {
  automatic: true
}
@EndUserText.label: 'Finance Document BW Source'
define view ZI_FI_DOC_BW_SOURCE
  as select from bkpf
  inner join bseg
    on bkpf.mandt = bseg.mandt
    and bkpf.belnr = bseg.belnr
    and bkpf.gjahr = bseg.gjahr
    and bkpf.bukrs = bseg.bukrs
{
  key bkpf.belnr as DocumentNumber,
      bkpf.bukrs as CompanyCode,
      bkpf.gjahr as FiscalYear,
      bseg.dmbtr as Amount,
      bseg.hkont as GLAccount
}

